import React from 'react';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, PieChart, Pie, Cell } from 'recharts';

const trendData = [
  { name: 'May 14', orders: 60 },
  { name: 'May 15', orders: 105 },
  { name: 'May 16', orders: 80 },
  { name: 'May 17', orders: 100 },
  { name: 'May 18', orders: 105 },
  { name: 'May 19', orders: 180 },
  { name: 'May 20', orders: 140 },
];

const statusData = [
  { name: 'Received', value: 18, color: '#94a3b8' },
  { name: 'In Cleaning', value: 42, color: '#3b82f6' },
  { name: 'Ready', value: 35, color: '#22c55e' },
  { name: 'Out for Delivery', value: 8, color: '#f97316' },
  { name: 'Delivered', value: 25, color: '#a855f7' },
];

export const OrdersTrendChart: React.FC = () => {
  return (
    <div className="card">
      <div className="card-header">
        <div className="card-title">Orders Trend</div>
        <select style={{ padding: '4px 8px', borderRadius: '4px', border: '1px solid #e2e8f0', outline: 'none' }}>
          <option>Last 7 days</option>
        </select>
      </div>
      <div style={{ width: '100%', height: 250 }}>
        <ResponsiveContainer width="100%" height="100%">
          <LineChart data={trendData} margin={{ top: 5, right: 20, left: -20, bottom: 5 }}>
            <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
            <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{ fontSize: 12, fill: '#64748b' }} dy={10} />
            <YAxis axisLine={false} tickLine={false} tick={{ fontSize: 12, fill: '#64748b' }} />
            <Tooltip />
            <Line type="monotone" dataKey="orders" stroke="#3b82f6" strokeWidth={3} dot={false} activeDot={{ r: 8 }} />
          </LineChart>
        </ResponsiveContainer>
      </div>
    </div>
  );
};

export const OrdersStatusChart: React.FC = () => {
  return (
    <div className="card" style={{ height: '320px' }}>
      <div className="card-title" style={{ marginBottom: '16px' }}>Orders by Status</div>
      <div style={{ display: 'flex', alignItems: 'center' }}>
        <div style={{ width: '50%', height: 200 }}>
          <ResponsiveContainer width="100%" height="100%">
            <PieChart>
              <Pie
                data={statusData}
                innerRadius={60}
                outerRadius={80}
                paddingAngle={2}
                dataKey="value"
              >
                {statusData.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={entry.color} />
                ))}
              </Pie>
              <Tooltip />
            </PieChart>
          </ResponsiveContainer>
        </div>
        <div style={{ width: '50%', paddingLeft: '16px' }}>
          <ul style={{ listStyle: 'none', padding: 0, margin: 0, fontSize: '13px' }}>
            {statusData.map((item, idx) => (
              <li key={idx} style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '12px' }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                  <div style={{ width: '8px', height: '8px', borderRadius: '50%', backgroundColor: item.color }}></div>
                  <span>{item.name}</span>
                </div>
                <div>
                  <span style={{ fontWeight: 600 }}>{item.value}</span>
                  <span style={{ color: '#64748b', marginLeft: '4px' }}>({Math.round((item.value / 128) * 100)}%)</span>
                </div>
              </li>
            ))}
          </ul>
        </div>
      </div>
    </div>
  );
};
